import{_ as n,o as h,c as a,ag as i}from"./chunks/framework.BZohXCq9.js";const d=JSON.parse('{"title":"[Client/App] Kho tính năng: Luồng Checkout (Booking UX)","description":"","frontmatter":{},"headers":[],"relativePath":"99-tham-khao/archive/03-kho-tinh-nang/dat-cho-thanh-toan/client-checkout.md","filePath":"99-tham-khao/archive/03-kho-tinh-nang/dat-cho-thanh-toan/client-checkout.md"}'),e={name:"99-tham-khao/archive/03-kho-tinh-nang/dat-cho-thanh-toan/client-checkout.md"};function o(l,t,c,g,r,s){return h(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="client-app-kho-tinh-nang-luong-checkout-booking-ux" tabindex="-1">[Client/App] Kho tính năng: Luồng Checkout (Booking UX) <a class="header-anchor" href="#client-app-kho-tinh-nang-luong-checkout-booking-ux" aria-label="Permalink to &quot;[Client/App] Kho tính năng: Luồng Checkout (Booking UX)&quot;">​</a></h1><table tabindex="0"><thead><tr><th style="text-align:left;">Phiên bản</th><th style="text-align:left;">Ngày</th><th style="text-align:left;">Sprint</th><th style="text-align:left;">Nội dung thay đổi</th><th style="text-align:left;">Người thực hiện</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>v1.0</strong></td><td style="text-align:left;">26/03/2026</td><td style="text-align:left;"><a href="./../../02-quan-ly-sprint/sprint-4-dat-cho-thanh-toan/01-yeu-cau-nghiep-vu">Sprint 4</a></td><td style="text-align:left;">Khởi tạo mô tả luồng Checkout &amp; Thanh toán</td><td style="text-align:left;">PO</td></tr></tbody></table><hr><p>Quy trình giao dịch được tối ưu hóa cho tỷ lệ chuyển đổi (Conversion).</p><h2 id="_1-chon-lich-gia-booking-selector" tabindex="-1">1. Chọn Lịch &amp; Giá (Booking Selector) <a class="header-anchor" href="#_1-chon-lich-gia-booking-selector" aria-label="Permalink to &quot;1. Chọn Lịch &amp; Giá (Booking Selector)&quot;">​</a></h2><ul><li><strong>Tính năng</strong>: <ul><li>Lịch chọn ngày linh hoạt (Calendar).</li><li>Hiển thị giá tour theo loại hành khách (Người lớn/Trẻ em).</li></ul></li><li><strong>Phản hồi</strong>: Kiểm tra slot trống theo thời gian thực (Real-time availability check).</li></ul><h2 id="_2-thong-tin-hanh-khach-passenger-info" tabindex="-1">2. Thông tin Hành khách (Passenger Info) <a class="header-anchor" href="#_2-thong-tin-hanh-khach-passenger-info" aria-label="Permalink to &quot;2. Thông tin Hành khách (Passenger Info)&quot;">​</a></h2><ul><li><strong>Tính năng</strong>: <ul><li>Nhập thông tin liên hệ (SĐT, Email, Tên).</li><li>Form nhập liệu cho trẻ em (Tuổi, ghi chú ăn uống/dị ứng).</li></ul></li></ul><h2 id="_3-cong-thanh-toan-payment-gateway-logic" tabindex="-1">3. Cổng Thanh toán (Payment Gateway Logic) <a class="header-anchor" href="#_3-cong-thanh-toan-payment-gateway-logic" aria-label="Permalink to &quot;3. Cổng Thanh toán (Payment Gateway Logic)&quot;">​</a></h2><ul><li><strong>Tính năng</strong>: <ul><li>Thanh toán VNPay (QR Pay, ATM, Credit Card).</li><li>Thanh toán MoMo (App-to-app, QR Scan).</li><li>Hiển thị thông báo khi thanh toán thất bại kèm lỗi chi tiết từ cổng.</li></ul></li></ul><h2 id="_4-xac-nhan-đon-e-voucher-display" tabindex="-1">4. Xác nhận Đơn (E-Voucher Display) <a class="header-anchor" href="#_4-xac-nhan-đon-e-voucher-display" aria-label="Permalink to &quot;4. Xác nhận Đơn (E-Voucher Display)&quot;">​</a></h2><ul><li><strong>Tính năng</strong>: <ul><li>Mã đơn hàng (Booking ID) duy nhất.</li><li>Mã QR định danh đơn hàng tại app.</li></ul></li><li><strong>Engagment</strong>: Gửi Email + Notification xác nhận ngay sau khi IPN trả về thành công.</li></ul><hr><p><em>Giao diện đặt tour cho khách hàng.</em></p>',14)])])}const p=n(e,[["render",o]]);export{d as __pageData,p as default};
